const input = $input.first().json || {};
const body = (input.body && typeof input.body === 'object') ? input.body : {};

function clean(v) {
  return (v ?? '').toString().trim();
}

const idToken = clean(body.id_token ?? input.id_token);
const nombreForm = clean(body.nombre ?? body.nombre_form);
const apellidoForm = clean(body.apellido ?? body.apellido_form);

if (!idToken) {
  return [{
    json: {
      auth_valid: false,
      status_code: 400,
      message: 'Falta id_token',
      email: '',
      nombre: '',
      nombre_form: nombreForm,
      apellido_form: apellidoForm,
    },
  }];
}

let tokenInfo;
try {
  tokenInfo = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://oauth2.googleapis.com/tokeninfo',
    qs: { id_token: idToken },
    json: true,
  });
} catch (error) {
  return [{
    json: {
      auth_valid: false,
      status_code: 401,
      message: 'Google token invalido',
      email: '',
      nombre: '',
      nombre_form: nombreForm,
      apellido_form: apellidoForm,
    },
  }];
}

const expectedAud = '674090944474-uvnagnjnf92e0u7jc6jpd9uhhtl52a0v.apps.googleusercontent.com';
const aud = clean(tokenInfo.aud);
const azp = clean(tokenInfo.azp);
const iss = clean(tokenInfo.iss);
const email = clean(tokenInfo.email).toLowerCase();
const emailVerifiedRaw = tokenInfo.email_verified;
const emailVerified = emailVerifiedRaw === true || emailVerifiedRaw === 'true';
const issOk = iss === 'accounts.google.com' || iss === 'https://accounts.google.com';
const audOk = expectedAud ? (aud === expectedAud || azp === expectedAud) : true;

if (!email || !emailVerified || !issOk || !audOk) {
  return [{
    json: {
      auth_valid: false,
      status_code: 401,
      message: 'Google token invalido',
      email: '',
      nombre: '',
      nombre_form: nombreForm,
      apellido_form: apellidoForm,
    },
  }];
}

const nombreGoogle = clean(tokenInfo.name ?? tokenInfo.given_name ?? 'Usuario') || 'Usuario';
return [{
  json: {
    auth_valid: true,
    status_code: 200,
    message: '',
    email,
    nombre: nombreGoogle,
    nombre_form: nombreForm,
    apellido_form: apellidoForm,
  },
}];

const pgItems = $items('Postgres - auth tx', 0, 0) || [];
const base = pgItems[0]?.json || {};
const jwtOut = $input.first().json || {};
const token = jwtOut.token ?? null;

const clearCookie = 'ba_session=; Path=/; Max-Age=0; HttpOnly; Secure; SameSite=Lax';
const statusCodeIn = Number(base.status_code_in ?? 401);
const message = (base.message_in ?? (statusCodeIn === 400 ? 'Falta id_token' : 'Google token invalido')).toString();

if (!base.auth_valid || !base.user_id) {
  return [{
    json: {
      ...base,
      response_code: statusCodeIn,
      response_body: { ok: false, message },
      set_cookie: clearCookie,
      session_token: null,
      session_max_age: 0,
    },
  }];
}

if (!token) {
  return [{
    json: {
      ...base,
      response_code: 500,
      response_body: { ok: false, message: 'Token de session no generado' },
      set_cookie: clearCookie,
      session_token: null,
      session_max_age: 0,
    },
  }];
}

const nombreRaw = (base.nombre ?? '').toString().trim();
const parts = nombreRaw ? nombreRaw.split(/\s+/).filter(Boolean) : [];
const apellidoFromNombre = parts.length > 1 ? parts.slice(1).join(' ') : null;

const maxAge = 604800;
const cookie = 'ba_session=' + token + '; Path=/; Max-Age=' + maxAge + '; HttpOnly; Secure; SameSite=Lax';

return [{
  json: {
    ...base,
    response_code: 200,
    response_body: {
      ok: true,
      user_id: base.user_id,
      email: base.email,
      nombre: base.nombre,
      apellido: apellidoFromNombre ?? base.apellido ?? null,
      plan_id: base.plan_id ?? null,
      puede_crear_barberia: !!base.puede_crear_barberia,
    },
    set_cookie: cookie,
    session_token: token,
    session_max_age: maxAge,
  },
}];

